window.switchBranch = (branchId) => {
    const data = branchMaps[branchId];
    if (!data) return;

    // Update Map
    const mapFrame = document.getElementById('branch-map');
    const openMapsBtn = document.getElementById('open-maps-link');

    if (mapFrame) mapFrame.src = data.url;
    if (openMapsBtn) openMapsBtn.href = data.directUrl;

    const quickChat = document.getElementById('quick-chat-link');
    const directCall = document.getElementById('direct-call-link');
    const quickChatNum = document.getElementById('quick-chat-num');
    const directCallNum = document.getElementById('direct-call-num');

    const formattedPhone = `+91 ${data.phone.substring(0, 5)} ${data.phone.substring(5)}`;

    if (quickChat) quickChat.href = `https://wa.me/91${data.phone}`;
    if (directCall) directCall.href = `tel:+91${data.phone}`;
    if (quickChatNum) quickChatNum.innerText = formattedPhone;
    if (directCallNum) directCallNum.innerText = formattedPhone;

    document.querySelectorAll('.address-card').forEach(card => {
        const id = card.id.replace('card-', '');
        const branchColor = branchMaps[id]?.color || 'border-orange-500';

        if (card.id === `card-${branchId}`) {
            card.classList.add('active', branchColor);
            card.classList.remove('border-slate-100');
        } else {
            card.classList.remove('active', 'border-orange-500', 'border-blue-500', 'border-emerald-500');
            card.classList.add('border-slate-100');
        }
    });
};

// Testimonial & Counters
function updateTestimonialFade() {
    const cards = Array.from(document.querySelectorAll(".testimonial-card"));
    if (!cards.length) return;
    const scrollBottom = window.scrollY + window.innerHeight;
    const section = document.getElementById('testimonials');
    if (!section) return;
    const distanceToBottom = (window.scrollY + section.getBoundingClientRect().bottom) - scrollBottom;
    cards.forEach(c => c.style.opacity = 1);
    const fadeStartThreshold = 200;
    if (distanceToBottom < fadeStartThreshold) {
        const lastCards = cards.slice(-3);
        const progress = Math.min(1, (fadeStartThreshold - distanceToBottom) / fadeStartThreshold);
        lastCards.forEach((card, index) => {
            const delay = index * 0.15;
            let local = Math.max(0, Math.min(1, (progress - delay) / (1 - delay)));
            card.style.opacity = 1 - local * 0.85;
        });
    }
}
window.addEventListener("scroll", updateTestimonialFade, { passive: true });

function animateCounters() {
    document.querySelectorAll('.count').forEach(el => {
        const target = parseInt(el.dataset.target);
        const duration = 1600;
        const start = performance.now();
        function step(now) {
            const elapsed = now - start;
            const progress = Math.min(elapsed / duration, 1);
            const ease = 1 - Math.pow(1 - progress, 3);
            const value = Math.floor(ease * target);
            el.textContent = value >= 1000 ? (value / 1000).toFixed(0) + ',000' : value;
            if (progress < 1) requestAnimationFrame(step);
            else el.textContent = target >= 1000 ? target.toLocaleString() : target;
        }
        requestAnimationFrame(step);
    });
}

const statsSection = document.getElementById('stats');
if (statsSection) {
    new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            animateCounters();
        }
    }, { threshold: 0.3 }).observe(statsSection);
}

