function showTopics(section, lang, event) {
    const sidebar = document.getElementById("sidebar-" + section);
    const e = event || window.event;
    const clickedBtn = e ? (e.currentTarget || (e.target ? e.target.closest('.lang-btn') : null)) : null;

    if (clickedBtn && clickedBtn.dataset.active === "true") {
        const content = sidebar.querySelector('.flex.flex-col.w-full');
        if (content) {
            content.style.opacity = '0';
            content.style.transform = 'translateY(-10px)';
            content.style.transition = 'all 0.4s ease';
        }
        setTimeout(() => {
            sidebar.classList.add("hidden");
            sidebar.classList.remove("flex");
            sidebar.style.display = 'none';
            sidebar.dataset.isManuallyHidden = "true";
            clickedBtn.style.transform = "scale(1)";
            clickedBtn.style.boxShadow = "";
            delete clickedBtn.dataset.active;
            window.dispatchEvent(new Event('resize'));
        }, 400);
        return;
    }

    document.querySelectorAll(`[onclick*="${section}"]`).forEach(btn => {
        btn.style.transform = "scale(1)";
        btn.style.boxShadow = "";
        delete btn.dataset.active;
    });

    const data = topics[section][lang];
    if (clickedBtn) {
        clickedBtn.style.transform = "scale(1.05)";
        clickedBtn.style.boxShadow = `0 0 0 4px ${data.color}`;
        clickedBtn.dataset.active = "true";;
    }

    sidebar.classList.remove("hidden");
    sidebar.classList.add("flex");
    sidebar.style.display = 'flex';
    delete sidebar.dataset.isManuallyHidden;

    const list = document.getElementById("list-" + section);
    const syllabusItems = data.syllabus.split('•').map(s => s.trim());
    const syllabusCards = syllabusItems.map((item, i) => `
        <div class="px-3 py-1 bg-white border border-gray-100/10 rounded-full text-l font-semibold text-gray-700 shadow-sm hover:shadow-md transition-all cursor-default" style="opacity:0; transform: translateY(15px); animation: courseSlideUp 0.4s ease forwards; animation-delay: ${i * 0.08}s;">
            ${item}
        </div>
    `).join('');

    // MODIFICATION: Removed Java underline and reduced margin
    const descClass = 'text-slate-600 text-md leading-relaxed line-clamp-2';

    const contentHtml = `
        <style>
            @keyframes courseSlideUp { to { opacity: 1; transform: translateY(0); } }
        </style>
        <div class="flex flex-col w-full gap-2">
            <div class="flex items-start justify-between gap-4">
                <div class="w-full lg:w-3/4" style="opacity:0; transform: translateY(20px); animation: courseSlideUp 0.6s ease forwards; animation-delay: 0.1s;">
                    <h4 class="text-2xl font-bold mb-1 uppercase tracking-tight text-slate-900">${lang.replace('rn', 'React Native').replace('ui', 'UI/UX').replace('dapython', 'Data Analytics with python').replace('aiml', 'Artificial Intelligence & Machine Learning').replace('webdev', 'Web Development with Digital Marketing').replace('spring', 'Spring Boot').replace('powerbi', 'Power BI')}</h4>
                    <p class="${descClass}">
                        ${data.desc}
                    </p>
                </div>
                <!-- MODIFICATION: Show logo on mobile as well -->
                <div class="flex w-1/4 justify-end shrink-0" style="opacity:0; transform: translateY(20px); animation: courseSlideUp 0.6s ease forwards; animation-delay: 0.2s;">
                    <div class="bg-white p-2 rounded-2xl shadow-sm border border-slate-100">
                        <img src="${data.logo}" alt="${lang}" class="w-12 h-12 sm:w-20 sm:h-20 object-contain">
                    </div>
                </div>
            </div>

            <!-- Horizontal Line -->
             <div class="h-[2px] w-full bg-white/50 rounded"></div>

            <div class="w-full">
                <span class="text-[12px] font-black uppercase tracking-widest text-slate-500 block mb-3">Syllabus Highlights</span>
                <div class="flex flex-wrap gap-2">
                    ${syllabusCards}
                </div>
            </div>

            <div class="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-6" style="opacity:0; transform: translateY(20px); animation: courseSlideUp 0.6s ease forwards; animation-delay: 0.4s;">
                <div class="flex flex-wrap items-center justify-start gap-4 sm:gap-8 text-slate-600">
                    <div class="flex items-center gap-2.5">
                        <i class="fas fa-circle-check text-slate-700"></i>
                        <span class="text-sm sm:text-sm font-normal">1 Certificate</span>
                    </div>
                    <div class="flex items-center gap-2.5">
                        <i class="fas fa-briefcase text-slate-700"></i>
                        <span class="text-sm sm:text-sm font-normal">Real-time projects</span>
                    </div>
                    <div class="flex items-center gap-2.5">
                        <i class="fas fa-address-card text-slate-700"></i>
                        <span class="text-sm sm:text-sm font-normal">Live Support</span>
                    </div>
                     <div class="flex items-center gap-2.5">
                        <i class="fas fa-user-graduate text-slate-700"></i>
                        <span class="text-sm sm:text-sm font-normal">Internship</span>
                    </div>
                </div>
                <div class="w-full sm:w-auto flex justify-start sm:justify-end pb-4 sm:pb-0 mt-2 sm:mt-0">
                    <button type="button" onclick="sendToWhatsApp('${section.replace('prog', 'Programming').replace('fs', 'Full Stack').replace('da', 'Data Analytics').replace('design', 'Designing').replace('webdev', 'Web Development').replace('dsa', 'Data Structures & Algorithms').replace('powerbi', 'Power BI').replace('d')}')"
                        class="w-auto px-10 py-3 text-white bg-blue-600 rounded-xl font-bold text-lg transition-all transform">
                        Enroll Now
                    </button>
                </div>
            </div>
        </div>
    `;

    list.className = "w-full transition-all duration-500 ease-in-out";
    list.style.opacity = '1';
    list.style.transform = 'translateY(0)';
    list.innerHTML = contentHtml;
    window.currentSelectedCourse = lang;
    cacheCardMeta();
    updateAnimations();
    setTimeout(() => list.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 100);
}

function sendToWhatsApp(courseName) {
    var course = courseName || window.currentSelectedCourse || "General Inquiry";
    var displayCourse = course;

    if (course === "prog") displayCourse = "Programming";
    else if (course === "fs") displayCourse = "Full Stack";
    else if (course === "da") displayCourse = "Data Analytics";
    else if (course === "design") displayCourse = "Designing";
    else if (course === "General Inquiry") displayCourse = "General Enquiry";

    var phoneNumber = "919514076220";

    var message =
        "Hello,\n\n" +
        "I would like to enquire about your training programs and course offerings.\n\n" +
        "Selected Course: " + displayCourse + "\n\n" +
        "Please share the course details, timing, and available learning options.\n\n" +
        "Thank you.";

    var url =
        "https://wa.me/" +
        phoneNumber +
        "?text=" +
        encodeURIComponent(message);

    window.open(url, "_blank");
}


document.addEventListener('DOMContentLoaded', () => {
    const carousel = document.getElementById('trainers-scroll-container');
    if (!carousel) return;

    // Clone children for seamless scroll
    const items = Array.from(carousel.children);
    items.forEach(item => {
        const clone = item.cloneNode(true);
        carousel.appendChild(clone);
    });

    let isHovered = false;
    carousel.addEventListener('mouseenter', () => isHovered = true);
    carousel.addEventListener('mouseleave', () => isHovered = false);
    carousel.addEventListener('touchstart', () => isHovered = true);
    carousel.addEventListener('touchend', () => setTimeout(() => isHovered = false, 1500));

    setInterval(() => {
        if (!isHovered) {
            // If we've scrolled past the first set of items
            // Jump back to start continuously
            if (carousel.scrollLeft >= carousel.scrollWidth / 2) {
                carousel.scrollLeft -= carousel.scrollWidth / 2;
            } else {
                carousel.scrollLeft += 1;
            }
        }
    }, 20); // 50fps smooth auto-scroll
});


document.addEventListener('DOMContentLoaded', () => {
    const track = document.getElementById('about-image-track');
    const dots = document.querySelectorAll('#about-slider-dots button');
    let currentSlide = 0;
    const slideCount = 3;

    function goToSlide(index) {
        currentSlide = index;
        track.style.transform = `translateX(-${currentSlide * 100}%)`;

        dots.forEach((dot, i) => {
            if (i === currentSlide) {
                dot.classList.remove('bg-slate-300');
                dot.classList.add('bg-slate-800');
            } else {
                dot.classList.remove('bg-slate-800');
                dot.classList.add('bg-slate-300');
            }
        });
    }

    dots.forEach((dot, index) => {
        dot.addEventListener('click', () => {
            goToSlide(index);
        });
    });

    // Auto scroll
    setInterval(() => {
        goToSlide((currentSlide + 1) % slideCount);
    }, 3500);
});



// Open modal
document.querySelectorAll('.openModal').forEach(button => {
    button.addEventListener('click', () => {
        const target = button.getAttribute('data-target');
        const modal = document.getElementById(target);
        modal.classList.remove('hidden');
        modal.classList.add('flex');
    });
});

// Close modal
document.querySelectorAll('.closeModal').forEach(button => {
    button.addEventListener('click', () => {
        const target = button.getAttribute('data-target');
        const modal = document.getElementById(target);
        modal.classList.remove('flex');
        modal.classList.add('hidden');
    });
});


document.addEventListener('DOMContentLoaded', () => {
    const galleryItems = Array.from(document.querySelectorAll('.img-popup'));
    const modal = document.getElementById('gallery-modal');
    const mainImg = document.getElementById('gallery-main-img');
    const leftPreview = document.getElementById('gallery-preview-left');
    const rightPreview = document.getElementById('gallery-preview-right');
    const closeBtn = document.getElementById('close-gallery');
    const prevBtn = document.getElementById('prev-gallery');
    const nextBtn = document.getElementById('next-gallery');
    const currentLabel = document.getElementById('gallery-current');
    const totalLabel = document.getElementById('gallery-total');

    let currentIndex = 0;
    const totalItems = galleryItems.length;
    totalLabel.textContent = totalItems;

    const updateGallery = (index) => {
        currentIndex = (index + totalItems) % totalItems;
        const currentItem = galleryItems[currentIndex];
        const prevItem = galleryItems[(currentIndex - 1 + totalItems) % totalItems];
        const nextItem = galleryItems[(currentIndex + 1) % totalItems];

        mainImg.src = currentItem.getAttribute('href');
        leftPreview.src = prevItem.getAttribute('href');
        rightPreview.src = nextItem.getAttribute('href');
        currentLabel.textContent = currentIndex + 1;
    };

    galleryItems.forEach((item, index) => {
        item.addEventListener('click', (e) => {
            // Prevent default library behavior if possible
            e.preventDefault();
            e.stopPropagation();

            updateGallery(index);
            modal.classList.add('active');
            document.body.style.overflow = 'hidden';
        }, true); // Use capture to trigger before other scripts
    });

    const closeModal = () => {
        modal.classList.remove('active');
        document.body.style.overflow = '';
    };

    closeBtn.addEventListener('click', closeModal);
    modal.addEventListener('click', (e) => {
        if (e.target === modal || e.target.classList.contains('gallery-main-container')) {
            closeModal();
        }
    });

    prevBtn.addEventListener('click', () => updateGallery(currentIndex - 1));
    nextBtn.addEventListener('click', () => updateGallery(currentIndex + 1));

    // Keyboard navigation
    document.addEventListener('keydown', (e) => {
        if (!modal.classList.contains('active')) return;
        if (e.key === 'ArrowLeft') updateGallery(currentIndex - 1);
        if (e.key === 'ArrowRight') updateGallery(currentIndex + 1);
        if (e.key === 'Escape') closeModal();
    });
});


